mapper.select:
SELECT s.id, s.seat_code AS seatNo, COALESCE(sr.display_name, sr.room_name) AS roomName, s.has_power AS hasPower, s.is_window_side AS nearWindow, s.seat_status AS status, s.created_at AS createdAt FROM seats s JOIN study_rooms sr ON sr.id = s.study_room_id WHERE s.deleted_at IS NULL
AND s.seat_code LIKE CONCAT('%', #{q.search}, '%')
AND s.study_room_id = #{q.roomId}
AND s.seat_status = #{q.status}
AND s.has_power = #{q.hasPower}
ORDER BY sr.room_name, s.seat_code
